const item = $input.first().json;

const pendingRowsRaw = item.pendingRowsRaw ?? [];
const cancelledBookingId = String(item.bookingId ?? '').trim();
const cancelledExtRef = String(item.Ext?.["booking ref"] ?? item.ExtBookingRef ?? '').trim();

function safe(v) {
  return String(v ?? '').trim();
}

function isMeaningfulRow(row) {
  if (!Array.isArray(row)) return false;

  const joined = row.map(safe).join(' ').trim();
  if (!joined) return false;

  const firstCell = safe(row[0]).toLowerCase();

  if (firstCell.includes('tour') && safe(row[1]).toLowerCase() === 'hora') return false;
  if (firstCell.includes('aqui la oficina')) return false;
  if (joined.includes('PENDING_START')) return false;
  if (joined.includes('PENDING_END')) return false;
  if (joined.includes('MANUAL_TITLE')) return false;
  if (joined.includes('PENDING_TITLE')) return false;
  if (joined.includes('PENDING_HEADER')) return false;

  return true;
}

function rowToBookingObject(row) {
  return {
    Tour: safe(row[0]),
    Hora: safe(row[1]),
    ExtBookingRef: safe(row[2]),
    PAX: safe(row[3]),
    PAXTotal: safe(row[4]),
    Idioma: safe(row[5]),
    Contacto: safe(row[6]),
    Telefono: safe(row[7]),
    bookingId: safe(row[8]),
    rawRow: row,
  };
}

const existingBookings = pendingRowsRaw
  .filter(isMeaningfulRow)
  .map(rowToBookingObject);

const bookingFoundToCancel = existingBookings.some(b =>
  (cancelledBookingId && b.bookingId === cancelledBookingId) ||
  (cancelledExtRef && b.ExtBookingRef === cancelledExtRef)
);

const bookingsAfterRemoval = existingBookings.filter(b => {
  const sameBookingId =
    cancelledBookingId && b.bookingId === cancelledBookingId;

  const sameExtRef =
    cancelledExtRef && b.ExtBookingRef === cancelledExtRef;

  return !(sameBookingId || sameExtRef);
});

return [
  {
    json: {
      ...item,
      existingBookings,
      bookingFoundToCancel,
      bookingsAfterRemoval,
      existingBookingsCount: existingBookings.length,
      finalBookingsCount: bookingsAfterRemoval.length,
    },
  },
];

// ============================================================
// BOKUN -> CLEAN PAYLOAD (COMPATIBLE CON WEBHOOK + BACKFILL)
// ============================================================

const root = $json;
const b = root.body ?? root;

// =========================
// HELPERS
// =========================
const firstDefined = (...vals) => {
  for (const v of vals) {
    if (v !== undefined && v !== null && v !== '') return v;
  }
  return '';
};

const toStr = (v) => String(v ?? '').trim();

const pad2 = (v) => String(v).padStart(2, '0');

const safeNumber = (v) => {
  if (v === undefined || v === null || v === '') return 0;
  const n = Number(String(v).replace(',', '.').trim());
  return Number.isNaN(n) ? 0 : n;
};

const normalizeHour = (raw) => {
  const value = toStr(raw);

  if (!value) return '';

  // HH:MM o H:MM
  let m = value.match(/^(\d{1,2}):(\d{2})$/);
  if (m) return `${pad2(m[1])}:${m[2]}`;

  // datetime string tipo 2026-04-26T16:00:00
  m = value.match(/T(\d{2}):(\d{2})/);
  if (m) return `${m[1]}:${m[2]}`;

  // texto con hora dentro
  m = value.match(/(\d{1,2}):(\d{2})/);
  if (m) return `${pad2(m[1])}:${m[2]}`;

  return value;
};

const normalizeDateOnly = (value) => {
  const s = toStr(value);
  if (!s) return '';

  // YYYY-MM-DD o YYYY-MM-DD HH:mm:ss
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) {
    return s.slice(0, 10);
  }

  // DD.MM.YYYY o DD.MM.YYYY HH:mm
  let m = s.match(/^(\d{1,2})\.(\d{1,2})\.(\d{4})(?:\s+\d{1,2}:\d{2})?$/);
  if (m) {
    return `${m[3]}-${pad2(m[2])}-${pad2(m[1])}`;
  }

  // DD/MM/YYYY o DD/MM/YYYY HH:mm
  m = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})(?:\s+\d{1,2}:\d{2})?$/);
  if (m) {
    return `${m[3]}-${pad2(m[2])}-${pad2(m[1])}`;
  }

  return '';
};

const extractHour = (value) => {
  const s = toStr(value);
  if (!s) return '';

  let m = s.match(/T(\d{2}):(\d{2})/);
  if (m) return `${m[1]}:${m[2]}`;

  m = s.match(/\b(\d{1,2}):(\d{2})\b/);
  if (m) return `${pad2(m[1])}:${m[2]}`;

  return '';
};

const normalizeLanguage = (raw) => {
  const v = toStr(raw).toLowerCase();

  const languageMap = {
    en: 'Inglés',
    es: 'Español',
    fr: 'Francés',
    it: 'Italiano',
    de: 'Alemán',
    pt: 'Portugués',
    english: 'Inglés',
    ingles: 'Inglés',
    'inglés': 'Inglés',
    spanish: 'Español',
    espanol: 'Español',
    español: 'Español',
    castellano: 'Español',
    french: 'Francés',
    frances: 'Francés',
    francés: 'Francés',
    german: 'Alemán',
    aleman: 'Alemán',
    alemán: 'Alemán',
    italian: 'Italiano',
    italiano: 'Italiano',
    portuguese: 'Portugués',
    portugues: 'Portugués',
    portugués: 'Portugués',
  };

  return languageMap[v] ?? (v ? raw : 'Sin idioma');
};

const getDatePartsMadrid = (dateObj) => {
  const dateParts = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Europe/Madrid',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(dateObj);

  const year = dateParts.find(p => p.type === 'year')?.value ?? '';
  const month = dateParts.find(p => p.type === 'month')?.value ?? '';
  const day = dateParts.find(p => p.type === 'day')?.value ?? '';

  return { year, month, day };
};

const getTimeMadrid = (dateObj) => {
  const timeParts = new Intl.DateTimeFormat('en-GB', {
    timeZone: 'Europe/Madrid',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  }).formatToParts(dateObj);

  const hour = timeParts.find(p => p.type === 'hour')?.value ?? '00';
  const minute = timeParts.find(p => p.type === 'minute')?.value ?? '00';

  return `${hour}:${minute}`;
};

// =========================
// DETECCIÓN DE FORMATO
// =========================
const isBackfill =
  b.importType === 'historical_backfill' ||
  b.source === 'bokun_export';

// =========================
// 0) TIPO DE EVENTO / ESTADO
// =========================
const actionRaw = firstDefined(
  root.query?.action,
  b.actionRaw,
  b.action,
  ''
);

const statusRaw = firstDefined(
  b.Status,
  b.status,
  b.bookingStatus,
  ''
);

const action = String(actionRaw).toUpperCase().trim();
const status = String(statusRaw).toUpperCase().trim();

let eventType = 'BOOKING_CONFIRMED';

if (
  action.includes('CANCEL') ||
  status.includes('CANCEL')
) {
  eventType = 'BOOKING_CANCELLED';
} else if (
  action.includes('CONFIRM') ||
  status.includes('CONFIRM')
) {
  eventType = 'BOOKING_CONFIRMED';
}

const isCancellation = isBackfill
  ? false
  : eventType === 'BOOKING_CANCELLED';

// =========================
// 1) DATOS BÁSICOS
// =========================
const externalId = isBackfill
  ? firstDefined(b.productId, b.productExternalId, '')
  : firstDefined(b.product?.externalId, b.externalId, '');

const title = isBackfill
  ? firstDefined(b.productTitle, b.Tour, '')
  : firstDefined(b.title, b.product?.title, '');

const bookingId = isBackfill
  ? toStr(firstDefined(b.bookingId, ''))
  : toStr(firstDefined(
      b.bookingId,
      b.productConfirmationCode,
      b.confirmationCode,
      ''
    ));

const parentBookingId = isBackfill
  ? toStr(firstDefined(b.parentBookingId, ''))
  : toStr(firstDefined(b.parentBookingId, ''));

const extBookingRef = isBackfill
  ? toStr(firstDefined(
      b.ExtBookingRef,
      b['Ext. booking ref'],
      b.bookingId,
      ''
    ))
  : toStr(firstDefined(
      b.parentBooking?.externalBookingReference,
      b.externalBookingReference,
      b.confirmationCode,
      b.productConfirmationCode,
      b.bookingId,
      ''
    ));

const tour = isBackfill
  ? toStr(firstDefined(
      b.Tour,
      b.productTitle,
      title,
      externalId ? `${externalId} ${title}`.trim() : title
    ))
  : `${toStr(externalId)} ${toStr(title)}`.trim() || toStr(title);

// =========================
// 2) PAX
// =========================
let pax = '';
let paxTotal = 0;

if (isBackfill) {
  pax = toStr(firstDefined(b.PAX, '0'));
  paxTotal = safeNumber(firstDefined(b.PAXTotal, b['PAX Total'], b.PAX, 0));
} else {
  const totalParticipants = Number(b.totalParticipants ?? 0);
  paxTotal = totalParticipants;

  const quantities = b.quantityByPricingCategory ?? {};
  const categories = b.bookedPricingCategories ?? [];

  const paxParts = [];

  for (const category of categories) {
    const id = String(category.id);
    const qty = Number(quantities[id] ?? 0);
    if (!qty) continue;

    let label = category.title ?? 'Passenger';
    const lower = label.toLowerCase();

    if (qty > 1) {
      if (lower === 'adult') label = 'Adults';
      else if (lower === 'child') label = 'Children';
      else if (lower === 'infant') label = 'Infants';
      else if (lower === 'senior') label = 'Seniors';
      else label = `${label}s`;
    }

    paxParts.push(`${qty} ${label}`);
  }

  pax = paxParts.length
    ? `${totalParticipants} (${paxParts.join(', ')})`
    : String(totalParticipants);
}

// =========================
// 3) IDIOMA
// =========================
const rawLanguage = isBackfill
  ? firstDefined(b.Idioma, '')
  : firstDefined(
      b.guidedLanguages?.[0]?.language,
      b.parentBooking?.language,
      b.language,
      b.locale,
      b.Idioma
    );

const idioma = isBackfill
  ? (toStr(b.Idioma) || 'Sin idioma')
  : normalizeLanguage(rawLanguage);

// =========================
// 4) CONTACTO
// =========================
let mainContact = '';

if (isBackfill) {
  mainContact = toStr(firstDefined(b.Contacto, 'Sin contacto'));
} else {
  const customerFirstName = firstDefined(
    b.parentBooking?.customer?.firstName,
    b.customer?.firstName
  );

  const customerLastName = firstDefined(
    b.parentBooking?.customer?.lastName,
    b.customer?.lastName
  );

  mainContact = [customerLastName, customerFirstName]
    .filter(Boolean)
    .join(', ');

  if (!mainContact) {
    const leadPassenger = (b.pricingCategoryBookings ?? []).find(x => x.leadPassenger);
    const leadFirstName = firstDefined(
      leadPassenger?.passengerInfo?.firstName
    );
    const leadLastName = firstDefined(
      leadPassenger?.passengerInfo?.lastName
    );

    mainContact = [leadLastName, leadFirstName]
      .filter(Boolean)
      .join(', ');
  }

  if (!mainContact) {
    mainContact = firstDefined(
      b.parentBooking?.customer?.fullName,
      b.customer?.fullName,
      ''
    );
  }

  if (!mainContact) {
    mainContact = 'Sin contacto';
  }
}

// =========================
// 5) TELÉFONO / EMAIL
// =========================
let phoneNumber = '';
let email = '';

if (isBackfill) {
  const rawPhone = firstDefined(b.Telefono, '');
  phoneNumber = rawPhone ? `'${String(rawPhone).trim()}` : '';
  email = firstDefined(b.Email, '');
} else {
  let rawPhone = firstDefined(
    b.parentBooking?.customer?.phoneNumberLinkable,
    b.parentBooking?.customer?.phoneNumber,
    b.parentBooking?.customer?.contactDetails?.phoneNumber,
    b.customer?.phoneNumberLinkable,
    b.customer?.phoneNumber,
    (b.pricingCategoryBookings ?? []).find(x => x.leadPassenger)?.passengerInfo?.phoneNumber
  );

  phoneNumber = rawPhone ? `'${String(rawPhone).trim()}` : '';

  email = firstDefined(
    b.parentBooking?.customer?.email,
    b.parentBooking?.customer?.contactDetails?.email,
    b.customer?.email,
    (b.pricingCategoryBookings ?? []).find(x => x.leadPassenger)?.passengerInfo?.email,
    ''
  );
}

// =========================
// 6) FECHA Y HORA DEL SERVICIO
// =========================
let serviceDate = '';
let hora = '';
let startDateTime = '';

if (isBackfill) {
  serviceDate = normalizeDateOnly(firstDefined(b.serviceDate, b.startDate, ''));
  hora = normalizeHour(firstDefined(b.Hora, extractHour(b.startDateTime), ''));

  startDateTime =
    serviceDate && hora
      ? `${serviceDate}T${hora}:00`
      : '';
} else {
  const ts = firstDefined(
    b.startDateTime,
    b.date,
    Date.now()
  );

  const startDateObj = new Date(ts);

  const { year, month, day } = getDatePartsMadrid(startDateObj);
  serviceDate = `${year}-${month}-${day}`;

  if (typeof b.startTime === 'string' && b.startTime.trim()) {
    hora = normalizeHour(b.startTime.trim());
  } else {
    hora = getTimeMadrid(startDateObj);
  }

  startDateTime = toStr(b.startDateTime);
}

// Carpetas y nombre archivo
let yearFolder = '';
let monthFolder = '';
let fileName = '';

if (serviceDate) {
  const [year, month] = serviceDate.split('-');

  const monthNames = {
    '01': 'Enero',
    '02': 'Febrero',
    '03': 'Marzo',
    '04': 'Abril',
    '05': 'Mayo',
    '06': 'Junio',
    '07': 'Julio',
    '08': 'Agosto',
    '09': 'Septiembre',
    '10': 'Octubre',
    '11': 'Noviembre',
    '12': 'Diciembre',
  };

  yearFolder = year;
  monthFolder = `${month}_${monthNames[month] ?? month}`;
  fileName = `Reservas ${serviceDate}`;
}

// =========================
// 7) CLASIFICACIÓN DE HOJA
// =========================
const text = `${tour} ${title}`.toLowerCase().trim();
const hasAny = (arr) => arr.some(term => text.includes(term));

const privateTerms = [
  'private tour',
  'private four-hour walking tour of madrid',
  'private bike tour of madrid',
  'private tour of prado national museum with professional guide',
  "madrid's royal palace & prado museum private walking tour",
  'toledo private half day tour cathedral santo tome and synagoge',
  'toledo and segovia private tour with hotel pick up from madrid',
  'segovia and avila private tour with lunch and hotel pick up from madrid',
  'private tapas tour in malaga',
  'privado',
  'private'
];

const contrastesTerms = [
  'contrasts of madrid',
  'contrasts of madrid : salamanca, vallecas, china town, & austrias',
  'tour de contrastes',
  'contrastes'
];

const escorialTerms = [
  'escorial monastery and the valley of the fallen tour from madrid',
  'escorial monastery',
  'valley of the fallen',
  'el escorial',
  'escorial'
];

const museosTerms = [
  'prado museum guided tour with skip-the-line ticket',
  'picasso experience reina sofía museum',
  'guided tour thyssen museum skip the line',
  'guided tour of the archaeological museum',
  'prado museum',
  'prado national museum',
  'reina sofía museum',
  'thyssen museum',
  'archaeological museum',
  'prado',
  'thyssen',
  'reina sofia',
  'reina sofía'
];

const avilaTerms = [
  'madrid to avila & segovia: full-day highlights tour',
  'full-day tour to avila & segovia from madrid with lunch',
  'avila & segovia tour with tickets to monuments from madrid',
  'avila historic old town walking tour',
  'discover segovia: historic walking tour with official guide',
  'segovia full day trip from madrid',
  'avila',
  'ávila',
  'segovia'
];

const toledoTerms = [
  'toledo half-day tour with st tome church & synagoge from madrid',
  'toledo half day tour with cathedral, st tome church & synagoge',
  'toledo full-day walking tour with guide from madrid',
  'toledo day trip from madrid: self-guided tour with 7 monuments',
  'self-guided toledo day trip from madrid with panoramic train',
  "toledo tour from madrid: cathedral, synagogue & st. tome's church",
  'toledo and segovia with priority access to alcazar of segovia from madrid',
  'toledo',
  'st tome',
  'st. tome',
  'synagoge',
  'synagogue',
  'cathedral santo tome',
  'mosque-cathedral',
  'mosque cathedral',
  'jewish quarter',
  'mosque and alcazar guided tour',
  'mosque and alcazar'
];

const palacioTerms = [
  'madrid old town & royal palace walking tour skip the line ticket',
  'madrid royal palace and almudena cathedral guided tour',
  'royal palace of madrid small group skip the line ticket',
  'guided tour of the royal collections gallery',
  'madrid royal palace: guided tour of the royal collections gallery',
  'imperial madrid walking tour',
  'royal palace',
  'palacio',
  'almudena cathedral',
  'royal collections',
  'old town'
];

let sheetName = isBackfill
  ? firstDefined(b.sheetName, '')
  : '';

if (!sheetName) {
  if (hasAny(privateTerms)) {
    sheetName = 'Privados';
  } else if (hasAny(contrastesTerms)) {
    sheetName = 'Contrastes';
  } else if (hasAny(escorialTerms)) {
    sheetName = 'Escorial';
  } else if (hasAny(museosTerms)) {
    sheetName = 'Museos';
  } else if (hasAny(avilaTerms)) {
    sheetName = 'Ávila';
  } else if (hasAny(toledoTerms)) {
    sheetName = 'Toledo';
  } else if (hasAny(palacioTerms)) {
    sheetName = 'Palacio';
  } else {
    sheetName = 'Varios';
  }
}

const isPrivateSheet = sheetName === 'Privados';

// =========================
// 8) SALIDA FINAL
// =========================
return [
  {
    json: {
      eventType,
      Tour: tour,
      Hora: hora,
      'Ext. booking ref': extBookingRef,
      PAX: pax,
      'PAX Total': paxTotal,
      Idioma: idioma,
      Contacto: mainContact,
      Telefono: phoneNumber,
      Email: email,
      bookingId,
      parentBookingId,
      sheetName,
      isPrivateSheet,
      serviceDate,
      fileName,
      yearFolder,
      monthFolder,
      bookingStatus: status || eventType,
      actionRaw: action,
      isCancellation,
      startDateTime,
      rawLanguage,
    }
  }
];

function pad2(v) {
  return String(v).padStart(2, '0');
}

function normalizeHour(raw) {
  const value = String(raw ?? '').trim();

  if (!value) return '';

  // HH:MM o H:MM
  let m = value.match(/^(\d{1,2}):(\d{2})$/);
  if (m) return `${pad2(m[1])}:${m[2]}`;

  // datetime
  m = value.match(/T(\d{2}):(\d{2})/);
  if (m) return `${m[1]}:${m[2]}`;

  // texto con hora dentro
  m = value.match(/(\d{1,2}):(\d{2})/);
  if (m) return `${pad2(m[1])}:${m[2]}`;

  return value;
}

const item = $input.first().json;

const normalizedHora = normalizeHour(item.Hora);
const markerHour = normalizedHora.replace(':', '_');

const isPrivateSheet = item.sheetName === 'Privados' || item.isPrivateSheet === true;

let blockStartMarker = '';
let blockEndMarker = '';
let blockTitleMarker = '';

if (isPrivateSheet) {
  blockStartMarker = 'PRIVATE_PENDING_START';
  blockEndMarker = 'PRIVATE_PENDING_END';
  blockTitleMarker = 'PRIVATE_PENDING_TITLE';
} else {
  blockStartMarker = `BLOCK_${markerHour}_PENDING_START`;
  blockEndMarker = `BLOCK_${markerHour}_PENDING_END`;
  blockTitleMarker = `BLOCK_${markerHour}_PENDING_TITLE`;
}

return [
  {
    json: {
      ...item,
      normalizedHora,
      markerHour,
      isPrivateSheet,
      blockStartMarker,
      blockEndMarker,
      blockTitleMarker,
    },
  },
];

const item = $input.first().json;

const dropboxRootPath = String(item.dropboxRootPath ?? '').trim();
const yearFolder = String(item.yearFolder ?? '').trim();
const monthFolder = String(item.monthFolder ?? '').trim();
const fileName = String(item.fileName ?? '').trim();

const cleanPath = (path) => {
  return path
    .replace(/\/+/g, '/')
    .replace(/\/$/, '') || '/';
};

const joinPath = (...parts) => {
  const filtered = parts
    .filter(v => v !== undefined && v !== null && v !== '')
    .map(v => String(v).trim().replace(/^\/+|\/+$/g, ''));
  return cleanPath('/' + filtered.join('/'));
};

const yearFolderPath = joinPath(dropboxRootPath, yearFolder);
const monthFolderPath = joinPath(dropboxRootPath, yearFolder, monthFolder);
const dailyFilePath = joinPath(dropboxRootPath, yearFolder, monthFolder, fileName);

return [
  {
    json: {
      ...item,
      yearFolderPath,
      monthFolderPath,
      dailyFilePath,
    },
  },
];

const item = $input.first().json;

const values = item.values ?? [];
const blockStartMarker = String(item.blockStartMarker ?? '').trim();
const blockEndMarker = String(item.blockEndMarker ?? '').trim();

const unmatchedStartMarker = 'UNMATCHED_PENDING_START';
const unmatchedEndMarker = 'UNMATCHED_PENDING_END';

function rowContainsMarker(row, marker) {
  if (!Array.isArray(row) || !marker) return false;
  return row.some(cell => String(cell ?? '').trim() === marker);
}

function findMarkerIndexes(startMarker, endMarker) {
  let startRowIndex0 = -1;
  let endRowIndex0 = -1;

  for (let i = 0; i < values.length; i++) {
    const row = values[i];

    if (startRowIndex0 === -1 && rowContainsMarker(row, startMarker)) {
      startRowIndex0 = i;
    }

    if (endRowIndex0 === -1 && rowContainsMarker(row, endMarker)) {
      endRowIndex0 = i;
    }
  }

  const markersFound =
    startRowIndex0 !== -1 &&
    endRowIndex0 !== -1 &&
    endRowIndex0 > startRowIndex0;

  return {
    startRowIndex0,
    endRowIndex0,
    markersFound,
  };
}

// 1) Intentamos bloque horario normal
let result = findMarkerIndexes(blockStartMarker, blockEndMarker);
let usingUnmatchedFallback = false;
let resolvedStartMarker = blockStartMarker;
let resolvedEndMarker = blockEndMarker;

// 2) Si no existe, usamos fallback de horarios no contemplados
if (!result.markersFound) {
  const fallbackResult = findMarkerIndexes(unmatchedStartMarker, unmatchedEndMarker);

  if (fallbackResult.markersFound) {
    result = fallbackResult;
    usingUnmatchedFallback = true;
    resolvedStartMarker = unmatchedStartMarker;
    resolvedEndMarker = unmatchedEndMarker;
  }
}

const { startRowIndex0, endRowIndex0, markersFound } = result;

const startRowNumber = startRowIndex0 !== -1 ? startRowIndex0 + 1 : null;
const endRowNumber = endRowIndex0 !== -1 ? endRowIndex0 + 1 : null;

const pendingDataStartRowNumber =
  markersFound ? startRowNumber + 1 : null;

const pendingDataEndRowNumber =
  markersFound ? endRowNumber - 1 : null;

const pendingRowsRaw = markersFound
  ? values.slice(startRowIndex0 + 1, endRowIndex0)
  : [];

return [
  {
    json: {
      ...item,
      startRowIndex0,
      endRowIndex0,
      startRowNumber,
      endRowNumber,
      pendingDataStartRowNumber,
      pendingDataEndRowNumber,
      pendingRowsRaw,
      markersFound,
      usingUnmatchedFallback,
