function languageRank(language) {
  const lang = safe(language).toLowerCase();

  if (lang === 'español') return 1;
  if (lang === 'ingles' || lang === 'inglés') return 2;
  if (lang === 'francés' || lang === 'frances') return 3;
  if (lang === 'alemán' || lang === 'aleman') return 4;
  if (lang === 'italiano') return 5;
  if (lang === 'portugués' || lang === 'portugues') return 6;
  if (lang === 'otros' || lang === 'sin idioma') return 98;

  return 99;
}

const sortedBookings = [...bookings].sort((a, b) => {
  const langDiff = languageRank(a.Idioma) - languageRank(b.Idioma);
  if (langDiff !== 0) return langDiff;

  const refA = safe(a.ExtBookingRef);
  const refB = safe(b.ExtBookingRef);
  return refA.localeCompare(refB);
});

return [
  {
    json: {
      ...item,
      sortedBookings,
    },
  },
