  item["Ext. booking ref"] ??
  item.ExtBookingRef ??
  ''
).trim();

function safe(v) {
  return String(v ?? '').trim();
}

function isMeaningfulRow(row) {
  if (!Array.isArray(row)) return false;

  const joined = row.map(safe).join(' ').trim();
  if (!joined) return false;

  const firstCell = safe(row[0]).toLowerCase();

  // Quitamos títulos, headers o líneas de ayuda si se colaran dentro
  if (firstCell.includes('tour') && safe(row[1]).toLowerCase() === 'hora') return false;
  if (firstCell.includes('aqui la oficina')) return false;
  if (joined.includes('PENDING_START')) return false;
  if (joined.includes('PENDING_END')) return false;
  if (joined.includes('MANUAL_TITLE')) return false;
  if (joined.includes('PENDING_TITLE')) return false;
  if (joined.includes('PENDING_HEADER')) return false;

  return true;
}

function rowToBookingObject(row) {
  return {
    Tour: safe(row[0]),
    Hora: safe(row[1]),
    ExtBookingRef: safe(row[2]),
    PAX: safe(row[3]),
    PAXTotal: safe(row[4]),
    Idioma: safe(row[5]),
    Contacto: safe(row[6]),
    Telefono: safe(row[7]),
    bookingId: safe(row[8]),
    rawRow: row,
  };
}

const existingBookings = pendingRowsRaw
  .filter(isMeaningfulRow)
  .map(rowToBookingObject);

const duplicateFound = existingBookings.some(b =>
  (incomingBookingId && b.bookingId === incomingBookingId) ||
  (incomingExtRef && b.ExtBookingRef === incomingExtRef)
);

