  Contacto: safe(item.Contacto),
  Telefono: safe(item.Telefono),
  bookingId: incomingBookingId,
};

const bookingsAfterInsert = duplicateFound
  ? existingBookings
  : [...existingBookings, incomingBooking];

return [
  {
    json: {
      ...item,
      existingBookings,
      duplicateFound,
      incomingBooking,
      bookingsAfterInsert,
      existingBookingsCount: existingBookings.length,
      finalBookingsCount: bookingsAfterInsert.length,
    },
  },
];

const item = $input.first().json;

function safe(v) {
  return String(v ?? '').trim();
}

const serviceDate = safe(item.serviceDate);
const horaRaw = safe(item.Hora);

// Normalizamos hora a HH:mm
let normalizedHora = horaRaw;
if (/^\d{1}:\d{2}$/.test(normalizedHora)) {
  normalizedHora = '0' + normalizedHora;
}

const serviceDateTimeStr = `${serviceDate}T${normalizedHora}:00`;

let serviceDateTimeMadrid = null;
let hoursUntilService = null;
let isLateCancellation24h = false;
let lateCancellationReason = '';

try {
  const nowMadrid = $now.setZone('Europe/Madrid');
  const serviceDT = DateTime.fromISO(serviceDateTimeStr, { zone: 'Europe/Madrid' });

  if (!serviceDT.isValid) {
    lateCancellationReason = 'Fecha/hora de servicio inválida';
  } else {
    serviceDateTimeMadrid = serviceDT.toFormat('yyyy-LL-dd HH:mm:ss');
    hoursUntilService = serviceDT.diff(nowMadrid, 'hours').hours;
    isLateCancellation24h = hoursUntilService < 24;
  }
} catch (error) {
  lateCancellationReason = error.message || 'Error calculando cancelación <24h';
}

return [
  {
    json: {
      ...item,
      serviceDateTimeMadrid,
      hoursUntilService,
      isLateCancellation24h,
      lateCancellationReason,
    },
  },
];
